// Parse Emergence Capital (emcap.com) - Enterprise SaaS pure-play
const items = $input.all();
const results = [];
const vcName = 'Emergence Capital';
const seen = new Set();
const today = new Date().toISOString().split('T')[0];

for (const item of items) {
  try {
    let html = item.json.data || item.json.body || (typeof item.json === 'string' ? item.json : '');
    if (!html || html.length < 100) {
      console.log('Emergence: No HTML content received');
      continue;
    }

    // emcap.com uses /portfolio/company-slug links
    // Pattern: <a href="/portfolio/company-name">...<img alt="Company Name">...</a>
    const portfolioPattern = /<a[^>]*href=["']\/portfolio\/([^"']+)["'][^>]*>[\s\S]*?<\/a>/gi;
    let match;

    while ((match = portfolioPattern.exec(html)) !== null) {
      const slug = match[1];
      const content = match[0];

      // Extract company name from alt text or convert slug
      let name = '';
      const altMatch = content.match(/alt=["']([^"']+)["']/i);
      if (altMatch) {
        name = altMatch[1].trim();
      } else {
        // Convert slug to name: 'my-company' -> 'My Company'
        name = slug.split('-').map(w => w.charAt(0).toUpperCase() + w.slice(1)).join(' ');
      }

      name = name.replace(/&amp;/g, '&');
      if (name.length < 2 || name.length > 50) continue;

      const key = name.toLowerCase().replace(/[^a-z0-9]/g, '');
      if (seen.has(key)) continue;
      seen.add(key);

      results.push({
        json: {
          'Company Name': name,
          'VC Firm': vcName,
          'Company Description': name + ' - Emergence Capital portfolio (Enterprise SaaS)',
          'Company URL': 'https://www.emcap.com/portfolio/' + slug,
          'Status': 'New',
          'First Seen Date': today,
          'Source': 'VC Portfolio'
        }
      });
    }
  } catch (e) {
    console.error('Emergence parse error:', e.message);
  }
}

return results.length ? results : [{ json: { _empty: true, _message: 'No companies found', vcName } }];

// Parse Insight Partners sitemap - 900+ B2B SaaS portfolio companies
// Source: sfcompany-sitemap.xml with URLs like /portfolio/company-slug/
const items = $input.all();
const results = [];
const vcName = 'Insight Partners';
const seen = new Set();
const today = new Date().toISOString().split('T')[0];

for (const item of items) {
  try {
    let xml = item.json.data || item.json.body || (typeof item.json === 'string' ? item.json : '');
    if (!xml || xml.length < 100) {
      console.log('Insight Partners: No sitemap content received');
      continue;
    }

    // Extract URLs from sitemap: <loc>https://www.insightpartners.com/portfolio/company-slug/</loc>
    const urlPattern = /<loc>https:\/\/www\.insightpartners\.com\/portfolio\/([^<\/]+)\/<\/loc>/gi;
    let match;

    while ((match = urlPattern.exec(xml)) !== null) {
      const slug = match[1];

      // Skip non-company pages
      if (slug === 'all' || slug === 'search' || slug.includes('page')) continue;

      // Convert slug to name: 'company-name' -> 'Company Name'
      // Handle special patterns: 'fka-oldname' means 'formerly known as'
      let name = slug
        .replace(/-fka-.*$/, '') // Remove 'formerly known as' suffix
        .replace(/-the-.*-group$/, '') // Remove group suffix
        .split('-')
        .map(w => w.charAt(0).toUpperCase() + w.slice(1))
        .join(' ');

      if (name.length < 2 || name.length > 60) continue;

      const key = name.toLowerCase().replace(/[^a-z0-9]/g, '');
      if (seen.has(key)) continue;
      seen.add(key);

      results.push({
        json: {
          'Company Name': name,
          'VC Firm': vcName,
          'Company Description': name + ' - Insight Partners portfolio (B2B SaaS)',
          'Company URL': 'https://www.insightpartners.com/portfolio/' + slug + '/',
          'Status': 'New',
          'First Seen Date': today,
          'Source': 'VC Portfolio'
        }
      });
    }
  } catch (e) {
    console.error('Insight Partners parse error:', e.message);
  }
}

console.log('Insight Partners: Found ' + results.length + ' companies from sitemap');
return results.length ? results : [{ json: { _empty: true, _message: 'No companies found', vcName } }];

