    // Fallback: look for any company-like headings
    if (results.length === 0) {
      const h3Pattern = /<h3[^>]*>([^<]{2,50})<\/h3>/gi;
      while ((match = h3Pattern.exec(html)) !== null) {
        const name = match[1].trim();
        if (name.length < 2) continue;
        if (/portfolio|company|sector|filter|view|about/i.test(name)) continue;
        const key = name.toLowerCase().replace(/[^a-z0-9]/g, '');
        if (seen.has(key)) continue;
        seen.add(key);

        results.push({
          json: {
            'Company Name': name,
            'VC Firm': vcName,
            'Company Description': name + ' - General Catalyst portfolio',
            'Company URL': '',
            'Status': 'New',
            'First Seen Date': today,
            'Source': 'VC Portfolio'
          }
        });
      }
    }
  } catch (e) {
    console.error('General Catalyst parse error:', e.message);
  }
}

return results.length ? results : [{ json: { _empty: true, _message: 'No companies found', vcName } }];

// Parse SignalFire - Data-driven VC, includes growth signals
// v1.4: Updated for new site structure - no more id=company-url
// Structure: portfolio---item cards with h3 names and external URLs
const items = $input.all();
const results = [];
const vcName = 'SignalFire';
const seen = new Set();
const today = new Date().toISOString().split('T')[0];

for (const item of items) {
  try {
    let html = item.json.data || item.json.body || (typeof item.json === 'string' ? item.json : '');
    if (!html || html.length < 100) {
      console.log('SignalFire: No HTML content received');
      continue;
    }

    // Primary: Match portfolio---item containing h3 name and external URL
    // Pattern: portfolio---item > h3[name] > a[href=https://external.com] (not signalfire.com)
    const cardPattern = /class=["'][^"']*portfolio---item[^"']*["'][^>]*>[\s\S]*?<h3[^>]*>([^<]+)<\/h3>[\s\S]*?<a[^>]*href=["'](https?:\/\/(?!signalfire\.com)[^"']+)["']/gi;
    let match;

    while ((match = cardPattern.exec(html)) !== null) {
      const name = match[1].trim().replace(/&amp;/g, '&');
      let url = match[2];

      if (name.length < 2 || name.length > 60) continue;
      // Skip internal portfolio links
      if (url.includes('/portfolio/')) continue;

      const key = name.toLowerCase().replace(/[^a-z0-9]/g, '');
      if (seen.has(key)) continue;
      seen.add(key);

      results.push({
        json: {
          'Company Name': name,
          'VC Firm': vcName,
          'Company Description': name + ' - SignalFire portfolio (data-driven VC)',
          'Company URL': url,
          'Status': 'New',
          'First Seen Date': today,
          'Source': 'VC Portfolio'
        }
      });
    }

    // Fallback: Try looser pattern - h3 names with nearby external URLs
    if (results.length === 0) {
      const namePattern = /<h3[^>]*>([^<]{2,50})<\/h3>/gi;
      const urlPattern = /<a[^>]*href=["'](https?:\/\/(?!signalfire\.com)[^"'\/portfolio][^"']+)["']/gi;
      const names = [];
      const urls = [];

      while ((match = namePattern.exec(html)) !== null) {
        const name = match[1].trim();
        if (name.length >= 2 && !/portfolio|sector|filter|all companies/i.test(name)) {
          names.push(name);
        }
      }
      while ((match = urlPattern.exec(html)) !== null) {
        if (!match[1].includes('/portfolio/')) urls.push(match[1]);
      }

      // Match names with URLs by position (both lists should align)
      const count = Math.min(names.length, urls.length);
      for (let i = 0; i < count; i++) {
        const name = names[i].replace(/&amp;/g, '&');
        const key = name.toLowerCase().replace(/[^a-z0-9]/g, '');
        if (seen.has(key)) continue;
        seen.add(key);

        results.push({
          json: {
            'Company Name': name,
            'VC Firm': vcName,
            'Company Description': name + ' - SignalFire portfolio',
            'Company URL': urls[i],
            'Status': 'New',
            'First Seen Date': today,
            'Source': 'VC Portfolio'
          }
        });
      }
    }

    // Last fallback: just h3 names (no URL)
    if (results.length === 0) {
      const h3Pattern = /class=["'][^"']*portfolio---item[^"']*["'][^>]*>[\s\S]*?<h3[^>]*>([^<]{2,50})<\/h3>/gi;
      while ((match = h3Pattern.exec(html)) !== null) {
        const name = match[1].trim();
        if (name.length < 2) continue;
        const key = name.toLowerCase().replace(/[^a-z0-9]/g, '');
        if (seen.has(key)) continue;
        seen.add(key);

        results.push({
          json: {
            'Company Name': name,
            'VC Firm': vcName,
            'Company Description': name + ' - SignalFire portfolio',
            'Company URL': '',
            'Status': 'New',
            'First Seen Date': today,
            'Source': 'VC Portfolio'
          }
        });
      }
    }
  } catch (e) {
    console.error('SignalFire parse error:', e.message);
  }
}

console.log('SignalFire: Found ' + results.length + ' companies');
return results.length ? results : [{ json: { _empty: true, _message: 'No companies found', vcName } }];

// Parse Iconiq Growth - B2B Enterprise + Healthcare
// v1.6: Fixed URL-name alignment - extract complete <a> blocks first
// Structure: <a href="url"><div class="companies-list_grid-item"><h2>Name</h2>...</div></a>
const items = $input.all();
const results = [];
const vcName = 'Iconiq Growth';
const seen = new Set();
const today = new Date().toISOString().split('T')[0];
const skipWords = ['milestone', 'insights', 'about', 'contact', 'team', 'news', 'blog', 'portfolio', 'growth', 'capital', 'iconiq', 'privacy', 'cookie', 'terms'];

for (const item of items) {
  try {
    let html = item.json.data || item.json.body || (typeof item.json === 'string' ? item.json : '');
    if (!html || html.length < 100) {
      console.log('Iconiq: No HTML content received');
      continue;
    }

    // Match complete <a>...</a> blocks to ensure URL-name alignment
    const linkPattern = /<a[^>]*href=["']([^"']+)["'][^>]*>([\s\S]*?)<\/a>/gi;
    let match;

    while ((match = linkPattern.exec(html)) !== null) {
      const url = match[1];
      const content = match[2];

      // Only process if this <a> contains a company card
      if (!content.includes('companies-list_grid-item')) continue;

      // Extract company name from h2 within this block
      const h2Match = content.match(/<h2[^>]*>([^<]+)<\/h2>/i);
      if (!h2Match) continue;

      const name = h2Match[1].trim().replace(/&amp;/g, '&');

      if (name.length < 2 || name.length > 60) continue;
      // Skip navigation/footer text
      if (skipWords.some(w => name.toLowerCase().includes(w))) continue;
      // Must be external URL (company website)
      if (!url.startsWith('http') || url.includes('iconiq.com') || url.includes('iconiqcapital.com')) continue;

      const key = name.toLowerCase().replace(/[^a-z0-9]/g, '');
      if (seen.has(key)) continue;
      seen.add(key);

      results.push({
        json: {
          'Company Name': name,
          'VC Firm': vcName,
          'Company Description': name + ' - Iconiq Growth portfolio (B2B Enterprise + Healthcare)',
          'Company URL': url,
          'Status': 'New',
          'First Seen Date': today,
          'Source': 'VC Portfolio'
        }
      });
    }
  } catch (e) {
    console.error('Iconiq parse error:', e.message);
  }
}

console.log('Iconiq: Found ' + results.length + ' companies');
return results.length ? results : [{ json: { _empty: true, _message: 'No companies found', vcName } }];

// Filter out empty results and dedupe across all VCs
const items = $input.all();
const results = [];
const seen = new Set();

for (const item of items) {
  // Skip empty markers
  if (item.json._empty) continue;

  const name = item.json['Company Name'] || '';
  if (!name || name.length < 2) continue;

  const key = name.toLowerCase().replace(/[^a-z0-9]/g, '');
  if (seen.has(key)) continue;
  seen.add(key);

  results.push(item);
}

console.log(`Growth Stage VCs: ${results.length} unique companies`);
return results.length ? results : [{ json: { _empty: true, _message: 'No companies from any VC' } }];
